// Поиск участников по кэшу (Postgres staff_users) — ПО ОДНОМУ ITEM НА ЧЕЛОВЕКА.
// ВХОД (из триггера, passthrough): subject, manager, witness1..witness3 (любое подмножество).
// ВЫХОД: item на каждого заполненного участника:
//   найден:    { role, query, found: true, staff_id, fio, post, city, office, email, login, source: 'cache' }
//   не найден: { role, query, found: false, debug: {...} } — debug показывает, что реально пришло из кэша.
const src = $('When Executed by Another Workflow').first().json || {};
const rows = $input.all().map(i => i.json || {});
const cache = rows.filter(r => r && (r.email || r.login || r.staff_id));

const norm = s => String(s == null ? '' : s).trim();
const low = s => norm(s).toLowerCase();
const fio = u => [u.surname, u.firstname, u.patronymic].filter(Boolean).join(' ');

const ROLES = ['subject', 'manager', 'witness1', 'witness2', 'witness3'];
const targets = ROLES.map(role => ({ role, query: norm(src[role]) })).filter(t => t.query);

function findInCache(query) {
  const q = low(query);
  const qLocal = q.includes('@') ? q.split('@')[0] : q.replace(/^kontur\\/, '');
  return cache.find(r => {
    const e = low(r.email);
    const l = low(r.login);
    const lLocal = l.replace(/^kontur\\/, '');
    return (!!e && (e === q || e.split('@')[0] === qLocal)) ||
           (!!l && (l === q || lLocal === q || lLocal === qLocal)) ||
           (/^\d+$/.test(q) && String(r.staff_id) === q);
  }) || null;
}

// диагностика состояния кэша — цепляется к каждому ненайденному
const debug = {
  cache_total: rows.length,
  cache_usable: cache.length,
  with_email: cache.filter(r => norm(r.email)).length,
  with_login: cache.filter(r => norm(r.login)).length,
  email_samples: cache.map(r => r.email).filter(Boolean).slice(0, 3),
  first_row_keys: Object.keys(rows[0] || {})
};

return targets.map(t => {
  const u = findInCache(t.query);
  return { json: u
    ? { role: t.role, query: t.query, found: true,
        staff_id: u.staff_id, fio: fio(u), post: u.post || null,
        city: u.town || null, office: u.officeTitle || null,
        email: u.email || null, login: u.login || null, source: 'cache' }
    : { role: t.role, query: t.query, found: false, debug }
  };
});

// Сводим всех не найденных в кэше в ОДИН item —
// чтобы выкачка Стаффа и upsert выполнились один раз, а не по разу на человека.
const missing = $input.all()
  .map(i => i.json || {})
  .filter(p => p && p.query)
  .map(p => ({ role: p.role, query: p.query }));

if (!missing.length) return [];
return [{ json: { missing } }];

// Упаковываем ВЕСЬ список Стаффа в один item для батч-upsert'а в Postgres.
// Дедуп по id. Если ни у одного item нет id — возвращаем диагностику вместо тишины.
const items = $input.all().map(i => i.json || {});

const pickId = u => u.id ?? u.userId ?? u.staffId ?? u.staff_id ?? null;

const seen = new Set();
const users = [];
for (const u of items) {
  const id = pickId(u);
  if (id == null || seen.has(id)) continue;
  seen.add(id);
  users.push({
    id,
    sid: u.sid ?? null, login: u.login ?? null, email: u.email ?? null,
    firstname: u.firstname ?? null, surname: u.surname ?? null, patronymic: u.patronymic ?? null,
    post: u.post ?? null,
    officeTown: (u.officeItem && u.officeItem.town) ?? null,
    officeId: (u.officeItem && u.officeItem.id) ?? null,
    officeTitle: (u.officeItem && u.officeItem.title) ?? null,
    innerPhone: u.innerPhone ?? null, mobilePhone: u.mobilePhone ?? null,
    statusId: u.statusId ?? null, status: u.status ?? null,
    birthday: u.birthday ?? null, photoPath: u.photoPath ?? null
  });
}

// диагностика: пришло много item'ов, но ни одного id — показываем структуру первого
if (!users.length) {
  const first = items[0] || {};
  return [{ json: {
    error: 'no_id_field',
    items_total: items.length,
    first_item_keys: Object.keys(first),
    hint: 'Проверь view у «Обращение в Стафф» (нужен light) или где реально лежит id'
  } }];
}

return [{ json: { users_json: JSON.stringify(users), count: users.length } }];

// Из свежего полного списка Стаффа отбираем тех, кого не было в кэше.
// ВЫХОД: item на найденного: { role, query, staff_id, source: 'staff' }.
// Кого нет и в Стаффе — отбрасываем (агент трактует отсутствие в ответе как not_found).
const all = $('Обращение в Стафф. Получение данных по всем').all().map(i => i.json || {});
const wanted = ($('Собрать отсутствующих').first().json || {}).missing || [];

const norm = s => String(s == null ? '' : s).trim();
const low = s => norm(s).toLowerCase();

function findInList(query) {
  const q = low(query);
  const qLocal = q.includes('@') ? q.split('@')[0] : q.replace(/^kontur\\/, '');
  return all.find(r => {
    const e = low(r.email);
    const l = low(r.login);
    const lLocal = l.replace(/^kontur\\/, '');
    return (!!e && (e === q || e.split('@')[0] === qLocal)) ||
           (!!l && (l === q || lLocal === q || lLocal === qLocal)) ||
           (/^\d+$/.test(q) && String(r.id) === q);
  }) || null;
}

return wanted
  .map(t => {
    const u = findInList(t.query);
    return u ? { json: { role: t.role, query: t.query, staff_id: u.id, source: 'staff' } } : null;
  })
  .filter(Boolean);

// Собираем расширенные профили: один плоский человек на item —
// та же форма, что после кэша, + department/organization/status из departmentItems.
// Контекст (role/query/source) берём из «Слить ветки», матчим по staff_id.
const ctxItems = $('Слить ветки').all().map(i => i.json || {});
const resp = $input.all().map(i => i.json || {});

const fio = p => [p.surname, p.firstname, p.patronymic].filter(Boolean).join(' ');
const byId = new Map(ctxItems.map(p => [String(p.staff_id), p]));

return resp.map((p, i) => {
  const ctx = (p && p.id != null && byId.get(String(p.id))) || ctxItems[i] || {};
  // ответ с ошибкой (onError: continueRegularOutput) или без id — отдаём как ненайденного
  if (!p || p.id == null) {
    const msg = (p && ((p.error && p.error.message) || p.message)) || 'нет ответа профиля';
    return { json: { role: ctx.role || null, query: ctx.query || null, staff_id: ctx.staff_id || null,
                     found: false, error: 'staff_error: ' + msg } };
  }
  const dep = (p.departmentItems && p.departmentItems[0]) || {};
  return { json: {
    role: ctx.role || null, query: ctx.query || null, found: true,
    staff_id: p.id, fio: fio(p),
    surname: p.surname || null, firstname: p.firstname || null, patronymic: p.patronymic || null,
    post: p.post || null,
    department: dep.title || null,
    organization: dep.organizationName || null,
    city: (p.officeItem && p.officeItem.town) || null,
    office: (p.officeItem && p.officeItem.title) || null,
    email: p.email || null, login: p.login || null, status: p.status || null,
    source: ctx.source || null
  } };
});

