CREATE TABLE IF NOT EXISTS hr_disciplinary_assistant.staff_users (
  staff_id BIGINT PRIMARY KEY,
  sid TEXT, login TEXT, email TEXT,
  firstname TEXT, surname TEXT, patronymic TEXT,
  post TEXT, town TEXT,
  office_id BIGINT, office_title TEXT,
  inner_phone TEXT, mobile_phone TEXT,
  status_id INT, status TEXT,
  birthday TEXT, photo_path TEXT,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);
CREATE INDEX IF NOT EXISTS idx_staff_users_email_lower ON hr_disciplinary_assistant.staff_users (lower(email));
CREATE INDEX IF NOT EXISTS idx_staff_users_login_lower ON hr_disciplinary_assistant.staff_users (lower(login));
